  9→
 10→const STORAGE_KEYS = {
 11→  apiKeys: 'citedby_api_keys',
 12→  webhooks: 'citedby_webhooks',
 13→};
 14→
 15→// ── Helpers ──
 16→
 17→const generateId = (): string =>
 18→  `${Date.now()}_${Math.random().toString(36).substring(2, 10)}`;
 19→
 20→const generateHex = (length: number): string => {
 21→  const chars = '0123456789abcdef';
 22→  let result = '';
 23→  for (let i = 0; i < length; i++) {
 24→    result += chars[Math.floor(Math.random() * chars.length)];
 25→  }
 26→  return result;
 27→};
 28→
 29→// ── API Keys ──
 30→
 31→export const getApiKeys = (): ApiKey[] => {
 32→  try {
 33→    const raw = localStorage.getItem(STORAGE_KEYS.apiKeys);
 34→    return raw ? JSON.parse(raw) : [];
 35→  } catch {
 36→    return [];
 37→  }
 38→};
 39→
 40→const saveApiKeys = (keys: ApiKey[]): void => {
 41→  localStorage.setItem(STORAGE_KEYS.apiKeys, JSON.stringify(keys));
 42→};
 43→
 44→export const createApiKey = (name: string): ApiKey => {
 45→  const newKey: ApiKey = {
 46→    id: generateId(),
 47→    name,
 48→    key: `cb_live_${generateHex(32)}`,
 49→    createdAt: new Date().toISOString(),
 50→    status: 'active',
 51→  };
 52→  const keys = getApiKeys();
 53→  keys.unshift(newKey);
 54→  saveApiKeys(keys);
 55→  return newKey;
 56→};
 57→
 58→export const revokeApiKey = (id: string): void => {
 59→  const keys = getApiKeys().map((k) =>
 60→    k.id === id ? { ...k, status: 'revoked' as const } : k
 61→  );
 62→  saveApiKeys(keys);
 63→};
 64→
 65→export const regenerateApiKey = (id: string): ApiKey | null => {
 66→  const keys = getApiKeys();
 67→  const index = keys.findIndex((k) => k.id === id);
 68→  if (index === -1) return null;
 69→  const updated: ApiKey = {
 70→    ...keys[index],
 71→    key: `cb_live_${generateHex(32)}`,
 72→    createdAt: new Date().toISOString(),
 73→    status: 'active',
 74→  };
 75→  keys[index] = updated;
 76→  saveApiKeys(keys);
 77→  return updated;
 78→};
 79→
 80→// ── Webhooks ──
 81→
 82→export const getWebhooks = (): Webhook[] => {
 83→  try {
 84→    const raw = localStorage.getItem(STORAGE_KEYS.webhooks);
 85→    return raw ? JSON.parse(raw) : [];
 86→  } catch {
 87→    return [];
 88→  }
 89→};
 90→
 91→const saveWebhooks = (webhooks: Webhook[]): void => {
 92→  localStorage.setItem(STORAGE_KEYS.webhooks, JSON.stringify(webhooks));
 93→};
 94→
 95→export const createWebhook = (url: string, events: WebhookEvent[]): Webhook => {
 96→  const webhook: Webhook = {
 97→    id: generateId(),
 98→    url,
 99→    events,
100→    active: true,
101→    lastDelivery: null,
102→    createdAt: new Date().toISOString(),
103→  };
104→  const webhooks = getWebhooks();
105→  webhooks.unshift(webhook);
106→  saveWebhooks(webhooks);
107→  return webhook;
108→};
109→
110→export const deleteWebhook = (id: string): void => {
111→  const webhooks = getWebhooks().filter((w) => w.id !== id);
112→  saveWebhooks(webhooks);
113→};
114→
115→export const toggleWebhook = (id: string): Webhook | null => {
116→  const webhooks = getWebhooks();
117→  const index = webhooks.findIndex((w) => w.id === id);
118→  if (index === -1) return null;
119→  webhooks[index] = { ...webhooks[index], active: !webhooks[index].active };
120→  saveWebhooks(webhooks);
121→  return webhooks[index];
122→};
