259→// ── Usage Data (mock) ──
260→
261→export const getUsageData = (): ApiUsageDay[] => {
262→  const days: ApiUsageDay[] = [];
263→  const now = new Date();
264→  for (let i = 29; i >= 0; i--) {
265→    const d = new Date(now);
266→    d.setDate(d.getDate() - i);
267→    const seed = d.getDate() + d.getMonth() * 31;
268→    const success = 20 + Math.round(((seed * 7 + i * 13) % 161));
269→    const errors = Math.round(((seed * 3 + i * 5) % 13));
270→    days.push({
271→      date: d.toISOString().split('T')[0],
272→      success,
273→      errors,
274→    });
275→  }
276→  return days;
277→};
278→
279→export const getUsageStats = (): ApiUsageStats => {
280→  const data = getUsageData();
281→  const totalSuccess = data.reduce((s, d) => s + d.success, 0);
282→  const totalErrors = data.reduce((s, d) => s + d.errors, 0);
283→  const total = totalSuccess + totalErrors;
284→  return {
285→    requestsPerDay: Math.round(total / data.length),
286→    errorRate: total > 0 ? Math.round((totalErrors / total) * 10000) / 100 : 0,
287→    avgLatency: 120 + Math.round(((data.length * 7) % 80)),
288→  };
289→};
