 74→export function computeNextRun(
 75→  freq: ScheduleFrequency,
 76→  hour: string,
 77→  dayOfWeek?: number,
 78→  dayOfMonth?: number
 79→): string {
 80→  const [h, m] = hour.split(':').map(Number);
 81→  const now = new Date();
 82→  const next = new Date(now);
 83→
 84→  next.setHours(h, m, 0, 0);
 85→
 86→  if (freq === 'daily') {
 87→    if (next <= now) {
 88→      next.setDate(next.getDate() + 1);
 89→    }
 90→  } else if (freq === 'weekly' && dayOfWeek !== undefined) {
 91→    const currentDay = next.getDay();
 92→    let daysUntil = dayOfWeek - currentDay;
 93→    if (daysUntil < 0 || (daysUntil === 0 && next <= now)) {
 94→      daysUntil += 7;
 95→    }
 96→    next.setDate(next.getDate() + daysUntil);
 97→  } else if (freq === 'monthly' && dayOfMonth !== undefined) {
 98→    next.setDate(dayOfMonth);
 99→    if (next <= now) {
100→      next.setMonth(next.getMonth() + 1);
101→      next.setDate(dayOfMonth);
102→    }
103→  }
104→
105→  return next.toISOString();
106→}
