122→export function checkAndRunPendingScans(): ScheduledScanResult[] {
123→  const now = new Date();
124→  const schedules = getSchedules();
125→  const history = getScheduledHistory();
126→  const newResults: ScheduledScanResult[] = [];
127→
128→  for (const schedule of schedules) {
129→    if (schedule.paused) continue;
130→    if (new Date(schedule.nextRun) > now) continue;
131→
132→    const result: ScheduledScanResult = {
133→      id: crypto.randomUUID(),
134→      scheduleId: schedule.id,
135→      brandName: schedule.brandName,
136→      url: schedule.url,
137→      executedAt: now.toISOString(),
138→      totalCitations: Math.floor(Math.random() * 36) + 5, // 5-40
139→      shareOfVoice: Math.round((Math.random() * 40 + 5) * 100) / 100, // 5-45
140→      trend: Math.round((Math.random() * 40 - 15) * 100) / 100, // -15 to +25
141→      status: 'completed',
142→    };
143→
144→    newResults.push(result);
145→    history.push(result);
146→
147→    schedule.lastRun = now.toISOString();
148→    schedule.nextRun = computeNextRun(
149→      schedule.frequency,
150→      schedule.hour,
151→      schedule.dayOfWeek,
152→      schedule.dayOfMonth
153→    );
154→  }
155→
156→  if (newResults.length > 0) {
157→    persistSchedules(schedules);
158→    persistHistory(history);
159→  }
160→
161→  return newResults;
162→}
