 93→    citationPresent: false,
 94→    excerpt: `I don't have specific verified data about ${brandName} in my training set, so I'd recommend checking their website directly at ${hostname}.`,
 95→  };
 96→
 97→  // ── Perplexity response: includes source citations ──
 98→  const perplexityResponse: AIEngineResponse = {
 99→    engine: 'Perplexity',
100→    response: `Based on recent analysis, the top solutions for ${query} in ${industryLabel} include ${mentionedCompetitors[0]} (ranked #1 by G2 in 2025) and ${mentionedCompetitors[1]} [1]. ${mentionedCompetitors[2]} is also frequently recommended for mid-size businesses [2]. ${brandName} does not currently appear in major comparison rankings for this category, though their website (${hostname}) indicates active development in this space [3].\n\nSources:\n[1] g2.com/categories/${industryLabel}\n[2] capterra.com/reviews\n[3] ${hostname}`,
101→    mentionType: 'absent',
102→    mentionScore: 10,
103→    sentiment: 'neutral',
104→    citationPresent: true,
105→    excerpt: `${brandName} does not currently appear in major comparison rankings for this category.`,
106→  };
107→
108→  // ── Gemini response: factual and data-driven ──
109→  const geminiResponse: AIEngineResponse = {
110→    engine: 'Gemini',
111→    response: `For "${query}", the ${industryLabel} market in 2025 is valued at approximately $XX billion globally. The primary vendors are ${mentionedCompetitors[0]} (market share ~25%), ${mentionedCompetitors[1]} (~18%), and ${mentionedCompetitors[2]} (~12%). ${brandName} is a newer entrant in this segment. According to available data, they offer services through ${hostname}, though detailed market share figures and independent reviews are limited at this time. Key selection criteria include pricing, integration capabilities, and customer support quality.`,
112→    mentionType: 'direct',
113→    mentionScore: 40,
114→    sentiment: 'neutral',
115→    citationPresent: false,
116→    excerpt: `${brandName} is a newer entrant in this segment. According to available data, they offer services through ${hostname}, though detailed market share figures and independent reviews are limited.`,
117→  };
118→
119→  // ── AI Overviews response: factual snippet with source links ──
120→  const aiOverviewsResponse: AIEngineResponse = {
121→    engine: 'AI Overviews',
122→    response: `${query}\n\nAccording to multiple sources, the leading solutions in ${industryLabel} include ${mentionedCompetitors[0]} and ${mentionedCompetitors[1]}. ${brandName} (${hostname}) is referenced as a specialized provider in this space, offering focused capabilities for ${industryLabel} professionals.\n\n• ${mentionedCompetitors[0]} — Enterprise-grade solution\n• ${mentionedCompetitors[1]} — Popular mid-market option\n• ${brandName} — Specialized ${industryLabel} tool\n\nSources: ${hostname}, g2.com, capterra.com`,
123→    mentionType: 'comparison',
124→    mentionScore: 45,
125→    sentiment: 'neutral',
126→    citationPresent: true,
127→    excerpt: `${brandName} (${hostname}) is referenced as a specialized provider in this space.`,
128→  };
129→
130→  const engines: AIEngineResponse[] = [
131→    chatgptResponse,
132→    claudeResponse,
133→    perplexityResponse,
134→    geminiResponse,
135→    aiOverviewsResponse,
136→  ];
137→
138→  // Calculate overall score as the average of all engine mention scores
139→  const overallScore = Math.round(
