207→        description: "Whether the engine includes a source citation or link for the brand",
208→      },
209→      excerpt: {
210→        type: Type.STRING,
211→        description: "The specific part of the response that mentions the brand, or empty string if absent",
212→      },
213→    },
214→    required: ['engine', 'response', 'mentionType', 'mentionScore', 'sentiment', 'citationPresent', 'excerpt'],
215→  };
216→
217→  const resultSchema: Schema = {
218→    type: Type.OBJECT,
219→    properties: {
