182→export const generateLlmJson = async (config: LlmJsonConfig): Promise<LlmJsonResult> => {
183→  const apiKey = getApiKey();
184→
185→  if (!apiKey) {
186→    console.warn("API_KEY not found, using llm.json simulation.");
187→    return fallbackSimulation(config);
188→  }
189→
190→  try {
191→    const ai = new GoogleGenAI({ apiKey });
192→
193→    const schema: Schema = {
194→      type: Type.OBJECT,
195→      properties: {
196→        llmJson: { type: Type.STRING, description: "The complete llm.json content as a stringified JSON object" },
197→        fieldCount: { type: Type.NUMBER, description: "Number of top-level fields in the generated JSON" },
198→        byteSize: { type: Type.NUMBER, description: "Approximate byte size of the JSON content" },
199→      },
200→      required: ["llmJson", "fieldCount", "byteSize"],
201→    };
202→
203→    const servicesDesc = config.services
204→      .filter(s => s.name)
205→      .map(s => `- ${s.name}: ${s.description}${s.url ? ` (${s.url})` : ''}`)
206→      .join('\n');
207→
208→    const keyPagesDesc = config.keyPages
209→      .filter(p => p.title && p.url)
210→      .map(p => `- ${p.title} (${p.url}): ${p.description}`)
211→      .join('\n');
212→
213→    const contactDesc = [
214→      `Email: ${config.contact.email}`,
215→      config.contact.phone ? `Phone: ${config.contact.phone}` : null,
216→      config.contact.address ? `Address: ${config.contact.address}` : null,
217→    ].filter(Boolean).join(', ');
218→
219→    const prompt = `
220→      INFORMATIONS DE L'ENTITE :
221→      - Nom : ${config.siteName}
222→      - URL : ${config.siteUrl}
223→      - Description : ${config.description}
224→      - Type d'entite : ${config.entity}
225→      ${config.industry ? `- Secteur d'activite : ${config.industry}` : ''}
226→      ${config.foundedYear ? `- Annee de creation : ${config.foundedYear}` : ''}
227→      ${config.targetAudience ? `- Audience cible : ${config.targetAudience}` : ''}
228→      ${config.languages && config.languages.length > 0 ? `- Langues : ${config.languages.join(', ')}` : ''}
229→
230→      SERVICES / PRODUITS :
231→      ${servicesDesc || 'Aucun renseigne'}
232→
233→      PAGES CLES :
234→      ${keyPagesDesc || 'Aucune renseignee'}
235→
236→      CONTACT :
237→      ${contactDesc}
238→
239→      ${config.socialLinks && config.socialLinks.length > 0 ? `PROFILS SOCIAUX :\n${config.socialLinks.map(l => `- ${l}`).join('\n')}` : ''}
240→
241→      MISSION :
242→      Genere un fichier llm.json complet, structure et optimise pour maximiser la citabilite de cette entite par les moteurs de reponse IA.
243→
244→      Le champ "llmJson" de ta reponse doit contenir le JSON complet stringify.
245→      Calcule fieldCount (nombre de cles de premier niveau) et byteSize (taille approximative en octets).
246→    `;
247→
248→    const response = await ai.models.generateContent({
249→      model: 'gemini-2.5-flash',
250→      contents: prompt,
251→      config: {
252→        systemInstruction: LLM_JSON_SYSTEM_PROMPT,
253→        responseMimeType: 'application/json',
254→        responseSchema: schema,
255→        temperature: 0.2,
256→      },
257→    });
258→
259→    let output = response.text;
260→    if (!output) {
261→      throw new Error("Empty response from AI");
262→    }
263→
264→    output = output.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
265→    const parsed = JSON.parse(output);
266→
267→    // Try to pretty-print the inner JSON if it was stringified
268→    let content = parsed.llmJson;
269→    try {
270→      const innerJson = JSON.parse(content);
271→      content = JSON.stringify(innerJson, null, 2);
272→    } catch {
273→      // Already a string or not valid JSON, keep as-is
274→    }
275→
276→    return {
277→      content,
278→      fieldCount: parsed.fieldCount,
279→      byteSize: parsed.byteSize,
280→    };
281→  } catch (error) {
282→    console.error("llm.json generation failed:", error);
283→    return fallbackSimulation(config);
284→  }
285→};
